<?php
 namespace WPAICG\Core; use WPAICG\Core\Moderation\AIPKit_BannedIP_Checker; use WPAICG\Core\Moderation\AIPKit_BannedWords_Checker; use WPAICG\Core\Moderation\AIPKit_Global_Security_Settings; use WPAICG\Core\Moderation\AIPKit_OpenAI_Moderation_Checker; use WP_Error; if (!defined('ABSPATH')) { exit; } class AIPKit_Content_Moderator { public static function check_content(string $text, array $context = []): ?WP_Error { $client_ip = $context['client_ip'] ?? null; $module = isset($context['module']) ? sanitize_key((string) $context['module']) : 'chat'; $bot_settings = $context['bot_settings'] ?? []; $global_blocklists = class_exists(AIPKit_Global_Security_Settings::class) ? AIPKit_Global_Security_Settings::get_blocklists_for_module($module) : [ 'banned_ips_settings' => ['ips' => '', 'message' => ''], 'banned_words_settings' => ['words' => '', 'message' => ''], ]; $banned_ips_settings = isset($global_blocklists['banned_ips_settings']) && is_array($global_blocklists['banned_ips_settings']) ? $global_blocklists['banned_ips_settings'] : ['ips' => '', 'message' => '']; $ip_check_result = AIPKit_BannedIP_Checker::check($client_ip, $banned_ips_settings); if (is_wp_error($ip_check_result)) { return $ip_check_result; } $banned_words_settings = isset($global_blocklists['banned_words_settings']) && is_array($global_blocklists['banned_words_settings']) ? $global_blocklists['banned_words_settings'] : ['words' => '', 'message' => '']; $words_check_result = AIPKit_BannedWords_Checker::check($text, $banned_words_settings); if (is_wp_error($words_check_result)) { return $words_check_result; } $openai_mod_check_result = AIPKit_OpenAI_Moderation_Checker::check($text, $bot_settings); if (is_wp_error($openai_mod_check_result)) { return $openai_mod_check_result; } return null; } } 